/**
* Представляет запись DwgObject.
*/
declare type xrel = Record<string, DwgObject>;

/**
* Представляет запись неизвестных данных.
*/
declare type xdata = Record<string, unknown>;

declare type Broadcast = Broadcast |
    'wdx:changeActiveLayer' |
    'wdx:changeActiveType' |
    'wdx:addEntity' |
    'wdx:deleteEntity' |
    'wdx:setx' |
    'wdx:view:activeLayerChanged' |
    'wdx:view:activeTypeChanged' |
    'wdx:add:layer' |
    'wdx:add:type' |
    'wdx:add:attachment' |
    'wdx:attachment:load' |
    'wdx:attachment:unload';

/**
* Представляет слушатель событий чертежа.
*/
declare type DrawingEventListener = (sender: DwgObject, id: DwgEvent, args?: Record<string, unknown>) => void;

/**
* Представляет объект чертежа.
*/
declare interface DwgObject {
    /**
     * Уникальный идентификатор объекта.
     */
    readonly $id?: string;

    /**
     * Путь объекта.
     */
    readonly $path: string;

    /**
     * Владелец объекта.
     */
    readonly owner?: DwgObject;

    /**
     * Корневой объект.
     */
    readonly root?: DwgObject;

    /**
     * Чертеж, содержащий объект.
     */
    readonly drawing?: Drawing;

    /**
     * Отношения объекта.
     */
    readonly rels: xrel;

    /**
     * Указывает, является ли объект агрегатом.
     */
    readonly aggregate: boolean;

    /**
     * Указывает, имеет ли объект отношения.
     */
    readonly hasRels: boolean;

    /**
     * Тип объекта.
     */
    readonly type: DwgType;

    /**
     * Получает отношение по его идентификатору.
     * @param id Идентификатор отношения.
     * @returns Отношение, или undefined, если не найдено.
     */
    getRel<T extends DwgObject>(id: string): T | undefined;

    /**
     * Добавляет отношение к объекту.
     * @param data Данные отношения.
     * @param id Идентификатор отношения.
     * @returns Обещание, которое разрешается добавленным отношением, или undefined, если не добавлено.
     */
    addRel(data?: xdata, id?: string): Promise<DwgObject | undefined>;

    /**
     * Удаляет отношение из объекта.
     * @param id Идентификатор отношения.
     * @returns Обещание, которое разрешается удаленным отношением, или undefined, если не удалено.
     */
    delRel(id: string): Promise<DwgObject | undefined>;

    /**
     * Начинает операцию обновления объекта.
     * @returns Обещание, которое разрешается, когда операция обновления начинается.
     */
    beginUpdate(): Promise<void>;

    /**
     * Завершает операцию обновления объекта.
     * @returns Обещание, которое разрешается, когда операция обновления завершается.
     */
    endUpdate(): Promise<void>;

    /**
     * Перебирает дочерние элементы объекта.
     * @param callback Функция обратного вызова для выполнения для каждого дочернего элемента.
     */
    forEach(callback: (obj: DwgObject) => boolean | void): void;

    /**
     * Ссылается на запись таблицы по ее имени и таблице.
     * @param name Имя записи таблицы.
     * @param table Таблица записи таблицы.
     * @returns Запись таблицы, или undefined, если не найдено.
     */
    reference<T extends DwgTableRecord>(name: string, table: string): T | undefined;

    /**
     * Устанавливает значение расширенных данных.
     * @param name Имя расширенных данных.
     * @param value Значение расширенных данных.
     * @returns Обещание, которое разрешается, когда расширенные данные установлены.
     */
    setx<T>(name: string, value: T): Promise<void>;

    /**
     * Получает значение расширенных данных.
     * @param name Имя расширенных данных.
     * @param value Значение по умолчанию расширенных данных.
     * @returns Значение расширенных данных, или значение по умолчанию, если не найдено.
     */
    getx<T>(name: string, value?: T): T | undefined;

    /**
     * Получает внешнюю ссылку по ее имени.
     * @param xref Имя внешней ссылки.
     * @returns Внешняя ссылка, или undefined, если не найдено.
     */
    xref<T extends DwgObject>(xref: string): T | undefined;

    /**
     * Получает ключи внешних ссылок.
     * @returns Ключи внешних ссылок.
     */
    xkeys(): string[];

    /**
    * Метод destroy используется для уничтожения объекта и всех его дочерних объектов.
    */
    destroy(): void;
}

/**
* Представляет чертеж.
*/
declare interface Drawing extends DwgObject {
    /**
     * Добавляет слушатель событий к чертежу.
     * @param callback Функция обратного вызова для выполнения при возникновении события.
     */
    addEventListener(callback: DrawingEventListener): void;

    /**
     * Удаляет слушатель событий из чертежа.
     * @param callback Функция обратного вызова для удаления.
     */
    removeEventListener(callback: DrawingEventListener): void;

    /**
     * Таблица стилей чертежа.
     */
    readonly styles: DwgTextStyleTable;

    /**
     * Таблица типов линий чертежа.
     */
    readonly linetypes: DwgLinetypeTable;

    /**
     * Таблица слоев чертежа.
     */
    readonly layers: DwgLayerTable;

    /**
     * Таблица блоков чертежа.
     */
    readonly blocks: DwgBlockTable;

    /**
     * Таблица макетов чертежа.
     */
    readonly layouts: DwgLayoutTable;

    /**
     * Таблица типов чертежа.
     */
    readonly types: DwgTypeTable;

    /**
     * Таблица материалов чертежа.
     */
    readonly materials: DwgMaterialTable;

    /**
     * Таблица геометрий чертежа.
     */
    readonly geometries: DwgGeometry3dTable;

    /**
     * Таблица групп чертежа.
     */
    readonly groups: DwgGroupTable;

    /**
     * Таблица вложений чертежа.
     */
    readonly attachments: DwgAttachmentTable;

    /**
     * Вложение чертежа.
     */
    readonly attachment?: DwgAttachment;

    /**
     * Главный чертёж проекта
     */
    readonly project: Drawing;

    /**
     * Настройки чертежа.
     */
    readonly settings?: WorkspaceSettings;

    /**
     * Контейнер для хранения данных чертежа
     */
    readonly workspace: WorkspaceItem;

    filterLayers(filter: string, strict: boolean = true): Set<DwgLayer>;

    filterEntities(filter: string, predicate?: (e: DwgEntity) => boolean, strict: boolean = true): DwgEntity[];
}

/**
* Представляет таблицу DwgTableRecord.
*/
declare interface DwgTable<T extends DwgTableRecord> extends DwgObject {
    /**
     * Активная запись таблицы.
     */
    active?: T;

    /**
     * Получает запись по ее имени.
     * @param name Имя записи.
     * @returns Запись, или undefined, если не найдено.
     */
    itemByName(name: string): T | undefined;

    /**
     * Получает запись по ее идентификатору.
     * @param id Идентификатор записи.
     * @returns Запись, или undefined, если не найдено.
     */
    itemById(id: string): T | undefined;

    /**
     * Перебирает записи таблицы.
     * @param callback Функция обратного вызова для выполнения для каждой записи.
     */
    forEach(callback: (obj: T) => boolean | void): void;

    /**
     * Поиск элемента
     */
    find(predicate: (obj: T) => boolean) : T | undefined;
}

