/**
* Интерфейс для пространственного индекса.
*/
declare interface SpatialIndex {
    /**
     * Обходит треугольники в видовой пирамиде.
     * @param frustum Видовая пирамида.
     * @param visitor Функция обратного вызова для выполнения для каждого треугольника.
     */
    walk(frustum: ViewFrustum, visitor: (triangle: number) => void): void;

    /**
     * Обходит треугольники в отрезке.
     * @param a Начало отрезка.
     * @param b Конец отрезка.
     * @param visitor Функция обратного вызова для выполнения для каждого треугольника.
     */
    walkSegment(a: vec3, b: vec3, visitor: (triangle: number) => void): void;

    /**
     * Обходит треугольники в луче.
     * @param ray Луч.
     * @param visitor Функция обратного вызова для выполнения для каждого треугольника.
     */
    walkRay(ray: ray3, visitor: (triangle: number) => void): void;

    /**
     * Обходит треугольники в плоскости.
     * @param plane Плоскость.
     * @param visitor Функция обратного вызова для выполнения для каждого треугольника.
     */
    walkPlane(plane: plane3, visitor: (triangle: number) => void): void;

    /**
     * Обходит треугольники в коробке.
     * @param box Коробка.
     * @param visitor Функция обратного вызова для выполнения для каждого треугольника.
     */
    walkBox(box: box3, visitor: (triangle: number) => void): void;

    /**
     * Границы пространственного индекса.
     */
    readonly bounds: box3;
}

